tasks.solution:
#include <iostream>
using namespace std;

int main() {
    int n, sum = 0;
    if (!(cin >> n)) return 0;

    // Loop from 1 to n
    for (int i = 1; i <= n; i++) {
        // Check if the current number is even
        if (i % 2 == 0) {
            sum += i;
        }
    }

    cout << sum << endl;
    return 0;
}

