tasks.solution:
#include <iostream>
using namespace std;

int main() {
    int num, digitSum = 0;
    if (!(cin >> num)) return 0;

    // Process each digit until the number becomes 0
    while (num > 0) {
        // Extract the last digit using the modulo operator
        int lastDigit = num % 10;

        // Add the digit to the running total
        digitSum += lastDigit;

        // Remove the last digit using integer division
        num = num / 10;
    }

    cout << digitSum << endl;
    return 0;
}
